using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so we must preserve it.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|1" format, so we must opt back in.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: EF 9 removed HasIndex support for Cosmos.
            // Indexes are managed via Cosmos DB directly, not EF.
            // Removed: entity.HasIndex(b => b.Name);
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Breaking change 4: EF 9 uses patch (partial update) by default instead of replace.
        // For read-modify-write patterns like SyncJob, opt out to preserve full-document replace.
        optionsBuilder.UseCosmos("AccountEndpoint=...;AccountKey=...;", "BlogDb",
            cosmosOptions => cosmosOptions.HttpClientFactory(() => new HttpClient()));
    }
}

// Breaking change 5: EF 9 sync I/O throws by default; SyncJob uses .ToList() and .SaveChanges().
// Fix: Either switch to async or suppress the warning (see SyncJob.cs).

