using Microsoft.EntityFrameworkCore;

class SyncJob
{
    // Breaking change 4: EF 9 Cosmos provider no longer supports sync I/O by default.
    // ToList() / SaveChanges() throw InvalidOperationException at runtime.
    // Fix: migrate to async equivalents.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

